import { differenceInMilliseconds, intervalToDuration } from 'date-fns';
import type { IntlShape } from 'react-intl';

import {
  getDifference,
  getSmallestCommonUnit,
} from './timeframe-calculations.js';
import type { TimeValue } from '../../../core/types/time.js';
import { TIMEFRAME_SELECTOR_MESSAGES } from '../constants/timeframeSelectorMessages.js';

/**
 * Formats and returns the duration of the timeframe.
 * @internal
 */
export function formatTimeframeDuration(
  from: TimeValue | null,
  to: TimeValue | null,
  intl: IntlShape,
): string {
  if (from === null || to === null) {
    return '';
  }

  if (from.type === 'iso8601' || to.type === 'iso8601') {
    const difference = intervalToDuration({
      start: from.absoluteDate,
      end: to.absoluteDate,
    });
    const diffInMilliseconds =
      differenceInMilliseconds(to.absoluteDate, from.absoluteDate) % 1000;

    return intl
      .formatMessage(TIMEFRAME_SELECTOR_MESSAGES.absoluteDateDuration, {
        years: Math.abs(difference.years ?? 0),
        months: Math.abs(difference.months ?? 0),
        days: Math.abs(difference.days ?? 0),
        hours: Math.abs(difference.hours ?? 0),
        minutes: Math.abs(difference.minutes ?? 0),
        seconds: Math.abs(difference.seconds ?? 0),
        milliseconds: Math.abs(diffInMilliseconds ?? 0),
      })
      .trim();
  }

  const difference = getDifference(from, to);
  const offsetUnit = getSmallestCommonUnit(from, to);

  const timeExpression =
    TIMEFRAME_SELECTOR_MESSAGES[
      `${offsetUnit}-duration` as keyof typeof TIMEFRAME_SELECTOR_MESSAGES
    ];
  return intl
    .formatMessage(timeExpression, {
      offset: Math.abs(difference === 0 ? 1 : difference),
    })
    .trim();
}
